+      env: {},
+      installDeps: () => {
+        throw new Error("workspace-only runtime deps should not install");
+      },
+      pluginId: "qa-channel",
+      pluginRoot,
+    });
+
+    expect(result).toEqual({ installedSpecs: [], retainSpecs: [] });
